module RefModule(
    input [1:0] sel,
    input A,
    input B,
    output Y
);wire obf_xor_out;
    wire and_out;
    wire or_out;
    wire nand_out;

    assign obf_xor_out = A ^ B;
    assign and_out = A & B;
    assign or_out = A | B;
    assign nand_out = ~(A & B);

    assign Y = (sel == 0) ? obf_xor_out :
               (sel == 1) ? and_out :
               (sel == 2) ? or_out :
                            nand_out;

endmodule
